//! Shared, platform-independent SQLite data lifecycle helpers.

use std::fs;
use std::path::{Path, PathBuf};

use rusqlite::{Connection, DatabaseName};

/// Create and integrity-check an online backup without overwriting an existing
/// destination. The temporary sibling is renamed only after verification.
pub fn backup_database(source: &Connection, destination: &Path) -> rusqlite::Result<()> {
    if destination.exists() {
        return Err(rusqlite::Error::InvalidPath(destination.to_path_buf()));
    }

    let temporary = temporary_path(destination);
    if temporary.exists() {
        fs::remove_file(&temporary).map_err(|_| rusqlite::Error::InvalidPath(temporary.clone()))?;
    }

    if let Some(parent) = destination.parent() {
        fs::create_dir_all(parent)
            .map_err(|_| rusqlite::Error::InvalidPath(parent.to_path_buf()))?;
    }

    let result = (|| {
        source.backup(DatabaseName::Main, &temporary, None)?;
        let backup = Connection::open(&temporary)?;
        let integrity: String = backup.query_row("PRAGMA integrity_check", [], |row| row.get(0))?;
        if integrity != "ok" {
            return Err(rusqlite::Error::InvalidQuery);
        }
        drop(backup);
        fs::rename(&temporary, destination)
            .map_err(|_| rusqlite::Error::InvalidPath(destination.to_path_buf()))?;
        Ok(())
    })();

    if result.is_err() {
        let _ = fs::remove_file(temporary);
    }
    result
}

fn temporary_path(destination: &Path) -> PathBuf {
    let mut name = destination.file_name().unwrap_or_default().to_os_string();
    name.push(".partial");
    destination.with_file_name(name)
}

#[cfg(test)]
mod tests {
    use super::*;

    fn destination(name: &str) -> PathBuf {
        std::env::temp_dir().join(format!("mindleak-storage-{name}-{}.db", std::process::id()))
    }

    #[test]
    fn online_backup_contains_committed_data() {
        let source = Connection::open_in_memory().unwrap();
        source
            .execute_batch("CREATE TABLE facts(value TEXT); INSERT INTO facts VALUES ('kept');")
            .unwrap();
        let path = destination("complete");
        let _ = fs::remove_file(&path);

        backup_database(&source, &path).unwrap();

        let backup = Connection::open(&path).unwrap();
        let value: String = backup
            .query_row("SELECT value FROM facts", [], |row| row.get(0))
            .unwrap();
        assert_eq!(value, "kept");
        drop(backup);
        fs::remove_file(path).unwrap();
    }

    #[test]
    fn backup_refuses_to_overwrite_existing_file() {
        let source = Connection::open_in_memory().unwrap();
        let path = destination("existing");
        fs::write(&path, "existing").unwrap();

        assert!(backup_database(&source, &path).is_err());
        assert_eq!(fs::read_to_string(&path).unwrap(), "existing");
        fs::remove_file(path).unwrap();
    }
}
